    }
    cout << "new connection from " << inet_ntoa(sin.sin_addr) << endl;

    while (len = recv(new_s, buf, sizeof(buf), 0)) {

        temp = buf;
        strcpy(fname, strtok(buf , " "));
            strcpy(lname, strtok(NULL, " "));
            strcpy(city , strtok(NULL, " "));
            strcpy(zip , strtok(NULL, " "));
